module top_module(
  input wire clk,
  input wire in_trigger,
  input wire in_reset,
  input wire [7:0] pulse_duration,
  output reg out_pulse  // Change to reg type
);reg [7:0] anti_counter;
  reg pulse_on;

  always @(posedge clk) begin
    if (in_reset) begin
      anti_counter <= 0;
      pulse_on <= 0;
      out_pulse <= 0;
    end else begin
      if (in_trigger) begin
        anti_counter <= pulse_duration;
        pulse_on <= 1;
        out_pulse <= 1;
      end else if (anti_counter > 0) begin
        anti_counter <= anti_counter - 1;
        out_pulse <= pulse_on;
      end else begin
        pulse_on <= 0;
        out_pulse <= 0;
      end
    end
  end

endmodule
